import{c as t,Q as a,j as o,m as i}from"./chunks/framework.CdiUUa3G.js";const u=JSON.parse('{"title":"ADR-011 — TypeScript throughout","description":"","frontmatter":{},"headers":[],"relativePath":"adr/ADR-011.md","filePath":"adr/ADR-011.md"}'),r={name:"adr/ADR-011.md"};function n(s,e,c,l,d,p){return a(),o("div",null,[...e[0]||(e[0]=[i('<h1 id="adr-011-—-typescript-throughout" tabindex="-1">ADR-011 — TypeScript throughout <a class="header-anchor" href="#adr-011-—-typescript-throughout" aria-label="Permalink to &quot;ADR-011 — TypeScript throughout&quot;">​</a></h1><blockquote><p>Status · Accepted Date · 2026-04-28 Supersedes · ADR-002 (vanilla JS) TA anchor · §stack</p></blockquote><h2 id="context" tabindex="-1">Context <a class="header-anchor" href="#context" aria-label="Permalink to &quot;Context&quot;">​</a></h2><p>ADR-002 chose vanilla JS on the basis that the rendering surfaces are imperative and a framework adds abstraction without benefit. That reasoning holds for the physics and rendering code. It does not hold for the application as a whole: stateful HUD panels, reactive telemetry values, multi-tab detail panels, dynamic card grids, and a data layer with complex JSON shapes are all harder to maintain and debug in untyped JavaScript at production scale. The orbital math library especially — <code>keplerPos</code>, <code>visViva</code>, <code>auToPx</code> — benefits directly from type-checked function signatures that catch unit errors at compile time.</p><h2 id="decision" tabindex="-1">Decision <a class="header-anchor" href="#decision" aria-label="Permalink to &quot;Decision&quot;">​</a></h2><p>TypeScript throughout. All source files in <code>src/</code> are <code>.ts</code> or <code>.svelte</code> (which supports TypeScript natively). The orbital library, data client, router, and all screen modules are typed. JSON data shapes are typed via interfaces in <code>src/types/</code>.</p><h2 id="rationale" tabindex="-1">Rationale <a class="header-anchor" href="#rationale" aria-label="Permalink to &quot;Rationale&quot;">​</a></h2><p>At the scale of millions of users and multiple contributors, untyped JavaScript becomes archaeology. TypeScript catches whole classes of bugs — wrong argument order in <code>keplerPos</code>, passing a string where a number is expected, accessing a field that doesn&#39;t exist on a mission record — at compile time rather than at runtime in a user&#39;s browser. The cost is marginal: Vite and SvelteKit both support TypeScript natively with zero additional configuration.</p><h2 id="alternatives-considered" tabindex="-1">Alternatives considered <a class="header-anchor" href="#alternatives-considered" aria-label="Permalink to &quot;Alternatives considered&quot;">​</a></h2><ul><li><strong>Vanilla JS with JSDoc types</strong> — provides IDE hints but no compile-time checking; fails silently in CI; rejected.</li><li><strong>Flow</strong> — less ecosystem support than TypeScript; no SvelteKit integration; rejected.</li></ul><h2 id="consequences" tabindex="-1">Consequences <a class="header-anchor" href="#consequences" aria-label="Permalink to &quot;Consequences&quot;">​</a></h2><p>Positive: compile-time error catching; self-documenting function signatures; contributor onboarding is faster when types describe data shapes explicitly. Negative: slightly more verbose; contributors must know TypeScript (low bar — it&#39;s a superset of JS).</p><h2 id="implementation-notes" tabindex="-1">Implementation notes <a class="header-anchor" href="#implementation-notes" aria-label="Permalink to &quot;Implementation notes&quot;">​</a></h2><p><code>tsconfig.json</code> at repo root. <code>strict: true</code>. All new files <code>.ts</code>. Existing prototype code ported during screen extraction in Slices 3–5.</p>',14)])])}const m=t(r,[["render",n]]);export{u as __pageData,m as default};
